Here's the full setup:

**XAML — wrap CollectionView in RefreshView for pull-to-refresh:**

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="48,*">
                    <Image Source="{Binding Icon}"
                           WidthRequest="40" HeightRequest="40" />
                    <VerticalStackLayout Grid.Column="1" VerticalOptions="Center">
                        <Label Text="{Binding Name}" FontAttributes="Bold" />
                        <Label Text="{Binding Description}"
                               FontSize="12" TextColor="Gray" />
                    </VerticalStackLayout>
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <Label Text="No items found."
                   HorizontalOptions="Center" VerticalOptions="Center" />
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

**ViewModel — using CommunityToolkit.Mvvm:**

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private bool isRefreshing;

    [ObservableProperty]
    private Item? selectedItem;

    public ObservableCollection<Item> Items { get; } = new();

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false;   // stops the spinner
        }
    }

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (SelectedItem is null) return;

        await Shell.Current.GoToAsync(
            $"detail?id={SelectedItem.Id}");

        SelectedItem = null;        // reset so user can re-select
    }
}
```

**Key bindings explained:**

| Property | Binding | Purpose |
|---|---|---|
| `IsRefreshing` | `TwoWay` (default on RefreshView) | Shows/hides spinner; set `false` when done |
| `Command` on RefreshView | `RefreshCommand` | Fires on pull-down gesture |
| `SelectionMode` | `Single` | Enables one-item selection |
| `SelectedItem` | `TwoWay` | Tracks the selected item; reset to `null` after navigation |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires when selection changes → navigates |

**Important notes:**
- Use `ObservableCollection<T>`, not `List<T>`, so adds/removes update the UI automatically.
- Always set `IsRefreshing = false` in a `finally` block so the spinner stops even on errors.
- Reset `SelectedItem = null` after navigating so the same item can be tapped again.
- Set `x:DataType` on the `DataTemplate` for compiled bindings (better perf + compile-time checks).
